  @fn layoutPortRow(nv, dir, mx, my, keep, forceSide)  @ 364
      @contract  face = forceSide, else derived from my; keep hides the mismatched kind during target hover.
  @fn slotHit(slots, mx, my)  @ 494
  @fn rowHit(rows, mx, my)  @ 504
